import akka.actor.ActorSystem
import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.stream.ActorMaterializer
import scala.concurrent.ExecutionContextExecutor

object WebhookProxyService {
  def main(args: Array[String]): Unit = {
    implicit val system: ActorSystem = ActorSystem("WebhookProxyService")
    implicit val materializer: ActorMaterializer = ActorMaterializer()
    implicit val executionContext: ExecutionContextExecutor = system.dispatcher

    val route =
      post {
        entity(as[String]) { url =>
          validateUrl(url) match {
            case Some(validUrl) =>
              onSuccess(Http().singleRequest(HttpRequest(uri = validUrl))) {
                case HttpResponse(status, headers, entity, _) =>
                  complete(HttpResponse(status = status, headers = headers, entity = entity))
                case _ => complete(StatusCodes.InternalServerError)
              }
            case None => complete(StatusCodes.BadRequest)
          }
        }
      }

    Http().bindAndHandle(route, "0.0.0.0", 8080)
      .onComplete {
        case scala.util.Success(binding) =>
          println(s"Server online at http://${binding.localAddress.getHostString}:${binding.localAddress.getPort}/")
        case scala.util.Failure(exception) =>
          println(s"Failed to bind to port: ${exception.getMessage}")
      }
  }

  private def validateUrl(url: String): Option[String] = {
    val allowedHosts = Set("example.com", "api.example.com") // Add your allowed hosts here
    url.parseUri.toOption.flatMap { uri =>
      if (allowedHosts.contains(uri.host.value)) Some(uri.toString)
      else None
    }
  }
}